"""Best effort runner for untrusted code generated by the model.

Runs code in a subprocess with a wall clock timeout, CPU time and memory
rlimits, inside an isolated temp working directory. Captures stdout, stderr,
and exit code. Kills the whole process group on timeout.

Known limits: no network isolation, inherits host PATH. For hard isolation
wrap the python call in firejail or a container. Enough for benchmark tasks.
"""

from __future__ import annotations

import os
import re
import resource
import signal
import subprocess
import sys
import tempfile
import time
from dataclasses import dataclass


@dataclass
class ExecResult:
    stdout: str
    stderr: str
    returncode: int
    timed_out: bool
    duration: float

    @property
    def passed(self) -> bool:
        return self.returncode == 0 and not self.timed_out


def _limits(cpu_seconds: int, mem_bytes: int):
    def apply():
        os.setsid()
        resource.setrlimit(resource.RLIMIT_CPU, (cpu_seconds, cpu_seconds))
        resource.setrlimit(resource.RLIMIT_AS, (mem_bytes, mem_bytes))
        resource.setrlimit(resource.RLIMIT_FSIZE, (50 * 1024 * 1024, 50 * 1024 * 1024))
    return apply


# The agent should only ever run pure functions. Refuse to execute a generation
# that shells out, opens a socket, or touches the filesystem destructively, so a
# stray or buggy generation can never delete the dataset or the repo. Override
# with TG_SANDBOX_GUARD=0. (rlimits are not a jail — for hard isolation against
# adversarial code run the whole process under firejail or in a container.)
_DANGEROUS = re.compile(
    r"\b(?:shutil|subprocess|socket)\b"
    r"|\bos\.(?:system|popen|remove|unlink|rmdir|removedirs|rename|replace)\b"
    r"|\brmtree\b|\brm\s+-rf\b"
    r"|__import__\s*\(\s*['\"](?:os|subprocess|shutil|socket)"
)


def _dangerous_ops(code: str) -> list[str]:
    return sorted({m.group(0) for m in _DANGEROUS.finditer(code)})


def run_code(
    code: str,
    timeout: float = 10.0,
    mem_limit_mb: int = 2048,
    workdir: str | None = None,
    guard: bool | None = None,
) -> ExecResult:
    if guard is None:
        guard = os.getenv("TG_SANDBOX_GUARD", "1") != "0"
    if guard:
        hits = _dangerous_ops(code)
        if hits:
            return ExecResult(
                stdout="",
                stderr=("SandboxGuard blocked: " + ", ".join(hits)
                        + " — this agent runs pure functions only; "
                        "set TG_SANDBOX_GUARD=0 to override."),
                returncode=126,
                timed_out=False,
                duration=0.0,
            )

    cpu_seconds = int(timeout) + 1
    mem_bytes = mem_limit_mb * 1024 * 1024

    tmp = None
    if workdir is None:
        tmp = tempfile.TemporaryDirectory(prefix="tg_sandbox_")
        workdir = tmp.name

    script = os.path.join(workdir, "candidate.py")
    with open(script, "w") as f:
        f.write(code)

    env = {
        "PATH": os.environ.get("PATH", ""),
        "PYTHONUNBUFFERED": "1",
        "HOME": workdir,
    }

    start = time.monotonic()
    proc = subprocess.Popen(
        [sys.executable, script],
        cwd=workdir,
        env=env,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        encoding="utf-8",
        errors="replace",
        preexec_fn=_limits(cpu_seconds, mem_bytes),
    )

    timed_out = False
    try:
        stdout, stderr = proc.communicate(timeout=timeout)
    except subprocess.TimeoutExpired:
        timed_out = True
        try:
            os.killpg(os.getpgid(proc.pid), signal.SIGKILL)
        except ProcessLookupError:
            pass
        stdout, stderr = proc.communicate()

    duration = time.monotonic() - start

    if tmp is not None:
        tmp.cleanup()

    return ExecResult(
        stdout=stdout or "",
        stderr=stderr or "",
        returncode=proc.returncode if proc.returncode is not None else -1,
        timed_out=timed_out,
        duration=duration,
    )


def run_with_tests(
    solution: str,
    test: str,
    timeout: float = 10.0,
    mem_limit_mb: int = 2048,
) -> ExecResult:
    code = solution + "\n\n" + test + "\n"
    return run_code(code, timeout=timeout, mem_limit_mb=mem_limit_mb)


if __name__ == "__main__":
    normal = run_code("print('hello'); print(2 + 2)")
    print("normal  :", normal.passed, repr(normal.stdout.strip()))

    boom = run_code("raise ValueError('boom')")
    last = boom.stderr.strip().splitlines()[-1] if boom.stderr else ""
    print("error   :", boom.returncode, repr(last))

    slow = run_code("while True: pass", timeout=2.0)
    print("timeout :", slow.timed_out, round(slow.duration, 2), "s")

    tested = run_with_tests("def add(a, b):\n    return a + b", "assert add(2, 3) == 5")
    print("tested  :", tested.passed)

    blocked = run_code("import shutil; shutil.rmtree('/tmp/x')")
    print("guard   :", blocked.returncode, repr(blocked.stderr[:38]))
